## ----debt-panel---------------------------------------------------------------
debt_panel <- data.frame(
  Country = c("United States", "United Kingdom"),
  `Debt/GDP (first)` = c("40.9% (1990)", "30.2% (1990)"),
  `Debt/GDP (latest)` = c("118.0% (2024)", "131.1% (2024)"),
  `Peak (year)` = c("126.4% (2020)", "194.7% (2020)"),
  Change = c("+77.0 pp", "+100.9 pp"),
  check.names = FALSE,
  stringsAsFactors = FALSE
)
knitr::kable(
  debt_panel,
  caption = "Central government debt, two advanced economies: first and latest observations plus peak. Data: World Bank \\texttt{GC.DOD.TOTL.GD.ZS}. The United Kingdom and the United States rose from roughly 30 to 40 per cent in 1990 to above 100 per cent by 2024.",
  booktabs = TRUE
)

